def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 10:
            for a in range(10, 0, -2):
                for b in range(1, a + 4):
                    val = ((ratio - a) ** 6) / (a * b * 0.85 + 0.5)
                    priority += val * np.sin(ratio * b / (a + 2))
            priority += (np.exp(ratio - 10) * np.cos(ratio * 1.3)) ** 2
            for z in range(5):
                priority += np.tanh(np.sin(ratio * (z + 1))) * 3
        elif 7 < ratio <= 10:
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 3):
                    comp = ((ratio - p) ** 4) * np.cos(ratio * p) / (q + 0.3)
                    priority += np.sin(comp) * 1.8
            priority += np.log(ratio) * 12 - np.tanh(ratio - 7) * 3
            for k in range(3, 8):
                priority += np.cos(ratio * k) / (k * 2)
        elif 4.5 <= ratio <= 7:
            s = 0
            for r in range(1, 20):
                s += ((ratio - 4.5) ** r) / (r * 1.5) * np.sin(r * ratio * 0.9)
            priority = (s * np.sin(9 * ratio)) - np.log(ratio) * 8 + np.tanh(5 * (7 - ratio)) * 2
            for n in range(1, 6):
                priority += np.cos(n * ratio * i) * ((ratio - 4.5) ** n) / (n + 1)
        elif 2 <= ratio < 4.5:
            s = 0
            for m in range(1, 15):
                s += ((4.5 - ratio) ** m) / (m ** 1.5 + 0.3)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.sin(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for w in range(1, 7):
                priority += np.cos(w * ratio * i) * ((ratio - 2) ** w) / w
        elif 1 <= ratio < 2:
            s = 0
            for x in range(1, 12):
                s += ((2 - ratio) ** x) / (x * 3) * np.sin(x * ratio * 1.5)
            priority = s
            if (i + int(item * 2)) % 5 == 1:
                priority *= np.log1p(bin_cap + 4) * 1.4
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.5)
            for j in range(1, 10):
                priority += ((2 - ratio) ** j) * np.cos(j * item * 1.5) * 0.8
        elif 0.5 <= ratio < 1:
            s = 0
            for y in range(1, 20):
                s += ((1 - ratio) ** y) / (y * 5)
            priority = s
            if (i * int(item * 1.4)) % 6 == 2:
                priority *= 2
            else:
                priority /= 1.8
            if bin_cap < item * 0.8:
                priority += np.log1p(item * bin_cap) * 3.5
            else:
                priority -= np.exp(-ratio * 1.5) * 2.5
            for v in range(1, 10):
                priority += ((1 - ratio) ** v) / (v * 4) * np.sin(item * v * 1.3)
        elif 0.2 <= ratio < 0.5:
            s = 0
            for t in range(1, 15):
                s += ((0.5 - ratio) ** t) / (t * 6) * np.cos(t * ratio * 2.5)
            priority = s + 1 / (bin_cap + 2)
            if int(item * 1.6) % 7 == 0:
                priority *= 3
            else:
                priority /= 3.5
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 8):
                priority += ((0.5 - ratio) ** u) / (u * 5) * np.cos(item * u * 1.1)
        else:
            s = 0
            for o in range(1, 18):
                s += ((0.2 - ratio) ** o) / (o * 7) * np.sin(o * item * 1.2)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 3:
                priority *= 4
            else:
                priority /= 4.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 6
            for n in range(1, 10):
                priority += ((0.2 - ratio) ** n) / (n * 8) * np.cos(item * n * 0.7)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 1:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.1) * 0.4
        if i % 4 == 1:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
